// src/api/chatApi.js
import axios from "axios";
import io from "socket.io-client";
const BASE_URL = "https://capavate.com";
const API_URL = `${BASE_URL}/api/user/chatmessage`;

let socket = null;

export const initSocket = (userId, userType) => {
  if (!socket) {
    // ✅ Add error handling and reconnection options
    socket = io(BASE_URL, {
      transports: ["websocket", "polling"], // ✅ Fallback to polling
      reconnection: true,
      reconnectionAttempts: 10,
      reconnectionDelay: 1000,
      reconnectionDelayMax: 5000,
      timeout: 20000,
    });

    socket.on("connect", () => {
      console.log("✅ Socket connected:", socket.id);
      socket.emit("user-online", { user_id: userId, user_type: userType });
    });

    socket.on("connect_error", (error) => {
      console.warn("⚠️ Socket connection error (non-critical):", error.message);
      // Don't throw error, just warn
    });

    socket.on("disconnect", (reason) => {
      console.log("🔴 Socket disconnected:", reason);
    });

    socket.on("reconnect", (attemptNumber) => {
      console.log("🔄 Socket reconnected after", attemptNumber, "attempts");
      socket.emit("user-online", { user_id: userId, user_type: userType });
    });
  } else {
    socket.emit("user-online", { user_id: userId, user_type: userType });
  }
  return socket;
};

export const getSocket = () => socket;

export const disconnectSocket = () => {
  if (socket) {
    socket.disconnect();
    socket = null;
  }
};

// ==================== API CALLS ====================

// Get or create conversation
export const getOrCreateConversation = async (
  participant1_type,
  participant1_id,
  participant2_type,
  participant2_id,
) => {
  try {
    const response = await axios.post(`${API_URL}/get-or-create-conversation`, {
      participant1_type,
      participant1_id,
      participant2_type,
      participant2_id,
    });
    return response.data;
  } catch (error) {
    console.error("Error getting/creating conversation:", error);
    throw error;
  }
};

// Get user conversations list
export const getUserConversations = async (user_type, user_id) => {
  try {
    const response = await axios.post(`${API_URL}/get-user-conversations`, {
      user_type,
      user_id,
    });
    return response.data;
  } catch (error) {
    console.error("Error getting conversations:", error);
    throw error;
  }
};

// Get messages for a conversation
export const getMessages = async (
  conversation_id,
  user_id,
  user_type,
  limit = 50,
  offset = 0,
) => {
  try {
    const response = await axios.post(`${API_URL}/get-messages`, {
      conversation_id,
      user_id,
      user_type,
      limit,
      offset,
    });
    return response.data;
  } catch (error) {
    console.error("Error getting messages:", error);
    throw error;
  }
};

// Send message
export const sendMessage = async (
  conversation_id,
  sender_type,
  sender_id,
  receiver_type,
  receiver_id,
  message,
) => {
  try {
    const response = await axios.post(`${API_URL}/send-message`, {
      conversation_id,
      sender_type,
      sender_id,
      receiver_type,
      receiver_id,
      message,
    });
    return response.data;
  } catch (error) {
    console.error("Error sending message:", error);
    throw error;
  }
};

// Delete message
export const deleteMessage = async (message_id, user_id, user_type) => {
  try {
    const response = await axios.post(`${API_URL}/delete-message`, {
      message_id,
      user_id,
      user_type,
    });
    return response.data;
  } catch (error) {
    console.error("Error deleting message:", error);
    throw error;
  }
};

// Upload file
export const uploadFile = async (formData) => {
  try {
    const response = await axios.post(`${API_URL}/upload-file`, formData, {
      headers: {
        "Content-Type": "multipart/form-data",
      },
    });
    return response.data;
  } catch (error) {
    console.error("Error uploading file:", error);
    throw error;
  }
};

// ==================== SOCKET EVENTS ====================

// Join a conversation room
export const joinConversation = (conversation_id) => {
  if (socket) {
    socket.emit("join-conversation", conversation_id);
  }
};

// Leave a conversation room
export const leaveConversation = (conversation_id) => {
  if (socket) {
    socket.emit("leave-conversation", conversation_id);
  }
};

// Emit typing start
export const emitTypingStart = (conversation_id, user_name) => {
  if (socket) {
    socket.emit("typing-start", { conversation_id, user_name });
  }
};

// Emit typing end
export const emitTypingEnd = (conversation_id, user_name) => {
  if (socket) {
    socket.emit("typing-end", { conversation_id, user_name });
  }
};

// Mark messages as read
export const emitMarkAsRead = (conversation_id, user_id, user_type) => {
  if (socket) {
    socket.emit("mark-as-read", { conversation_id, user_id, user_type });
  }
};

// ==================== SOCKET EVENT LISTENERS ====================

// Listen for new messages
export const onNewMessage = (callback) => {
  if (socket) {
    socket.on("new-message", callback);
  }
};

// Listen for typing status
export const onUserTyping = (callback) => {
  if (socket) {
    socket.on("user-typing", callback);
  }
};

// Listen for messages read status
export const onMessagesRead = (callback) => {
  if (socket) {
    socket.on("messages-read", callback);
  }
};

// Listen for user status change
export const onUserStatusChange = (callback) => {
  if (socket) {
    socket.on("user-status-change", callback);
  }
};

// Listen for message notifications
export const onMessageNotification = (callback) => {
  if (socket) {
    socket.on("message-notification", callback);
  }
};

// Remove all socket listeners
export const removeAllListeners = () => {
  if (socket) {
    socket.off("new-message");
    socket.off("user-typing");
    socket.off("messages-read");
    socket.off("user-status-change");
    socket.off("message-notification");
  }
};
